            if (i == j) {
                out[i][j] = 0d;
            } else {
                double r = correlationMatrix.getEntry(i, j);
                // Handle perfect correlation cases
                if (Math.abs(r) == 1) {
                    out[i][j] = 0d;
                } else {
                    double t = Math.abs(r) * Math.sqrt((nObs - 2) / (1 - r * r));
                    // Ensure numerical stability
                    if (Double.isInfinite(t)) {
                        t = Double.MAX_VALUE;
                    }
                    double pValue = 2 * (1 - tDistribution.cumulativeProbability(t));
                    // Ensure pValue is within valid range
                    out[i][j] = Math.max(pValue, Double.MIN_NORMAL);
                }
            }
        }
    }
    return new BlockRealMatrix(out);
}

public RealMatrix getCorrelationPValues() throws MathException {
    TDistribution tDistribution = new TDistributionImpl(nObs - 2);
    int nVars = correlationMatrix.getColumnDimension();
    double[][] out = new double[nVars][nVars];
    for (int i = 0; i < nVars; i++) {
        for (int j = 0; j < nVars; j++) {
            if (i == j) {
                out[i][j] = 0d;
            } else {
                double r = correlationMatrix.getEntry(i, j);
                if (Math.abs(r) == 1) {
                    out[i][j] = Double.MIN_VALUE; // Perfect correlation or anti-correlation
                } else {
                    double t = Math.abs(r) * Math.sqrt((nObs - 2) / (1 - r * r));
                    if (t > Double.MAX_VALUE) {
                        t = Double.MAX_VALUE;
                    }
                    double pValue = 2 * (1 - tDistribution.cumulativeProbability(t));
                    if (pValue <= 0) {
                        pValue = Double.MIN_VALUE;
                    }
                    out[i][j] = pValue;
                }
            }
        }
    }
    return new BlockRealMatrix(out);
}
